SELECT COUNT(1) FROM public."MonitoringPoints"
"IsDelete" = false
AND "CountyDistrict" = #{countyDistrict}

SELECT COUNT(1)
FROM public."MonitoringPoints" mp

    mp."IsDelete" = false

        AND mp."CountyDistrict" = #{countyDistrict}


        AND mp."Town" = #{town}


        AND mp."Village" = #{village}

SELECT
mp.*
FROM public."MonitoringPoints" mp

    mp."IsDelete" = false

        AND mp."CountyDistrict" = #{countyDistrict}


        AND mp."Town" = #{town}


        AND mp."Village" = #{village}


ORDER BY mp."MonitoringPointID" ASC
LIMIT #{limit} OFFSET #{offset}

SELECT unnest(COALESCE("ImagePaths", '{}'::text[])) AS path
FROM public."MonitoringPoints"
WHERE "MonitoringPointID" = #{monitoringPointID}

mapper.update:
UPDATE public."MonitoringPoints"
SET "ImagePaths" = COALESCE("ImagePaths", '{}') || ARRAY[#{path}::text]
WHERE "MonitoringPointID" = #{monitoringPointID}

  UPDATE public."MonitoringPoints"
  SET "ImagePaths" = ARRAY(
      SELECT unnest(COALESCE("ImagePaths", '{}'))
EXCEPT SELECT #{path}
                     )
  WHERE "MonitoringPointID" = #{monitoringPointID}
